evals.prompt:
This Vespa schema has multiple subtle bugs that will cause runtime issues. Find and fix ALL of them. Write the corrected schema to schemas/catalog.sd

schema catalog {
    document catalog {
        field title type string {
            indexing: summary | index
        }
        field sku type string {
            indexing: attribute
            match: exact
        }
        field status type bool {
            indexing: summary | attribute
            attribute: fast-access
        }
        field embedding type tensor<float>(x[256]) {
            indexing: summary | attribute
            attribute {
                distance-metric: angular
                fast-search
            }
            index {
                hnsw {
                    max-links-per-node: 16
                }
            }
        }
        field content type string {
            indexing: summary | attribute
            attribute: paged
        }
        field labels type weightedset<float> {
            indexing: summary | attribute
        }
    }
    fieldset default {
        fields: title, content
    }
    rank-profile search {
        first-phase {
            expression: bm25(title) + bm25(content)
        }
    }
}
